<span class="line"><span style="color:#CDD6F4;">    overhead </span><span style="color:#94E2D5;">+=</span><span style="color:#CDD6F4;"> counter</span><span style="color:#94E2D5;">.</span><span style="color:#89B4FA;font-style:italic;">count</span><span style="color:#9399B2;">(</span><span style="color:#CDD6F4;">system_prompt</span><span style="color:#9399B2;">);</span></span>
